class Solution {
public:
    int maxSubArray(vector<int>& nums) {
        int n = nums.size();
        int max_sum = nums[0];
        int current_sum = nums[0];
        for (int i = 1; i < n - 1; i++) {
            current_sum += nums[i];
            if (current_sum > max_sum) max_sum = current_sum;
            else if (current_sum < 0) current_sum = 0;
        }
        return max_sum;
    }
};

